using System;
using System.Collections.Generic;
using System.Xml;

public class ConfigParser
{
    public Dictionary<string, object> ParseConfig(string xmlContent)
    {
        var configSettings = new Dictionary<string, object>();
        
        try
        {
            var xmlDoc = new XmlDocument();
            xmlDoc.LoadXml(xmlContent);

            foreach (XmlNode node in xmlDoc.DocumentElement.ChildNodes)
            {
                if (node.NodeType == XmlNodeType.Element)
                {
                    string key = node.Name;
                    object value;

                    if (node.HasChildNodes && node.FirstChild.HasValue())
                    {
                        key += "." + node.FirstChild.InnerText;
                    }

                    switch (node.LocalName.ToLower())
                    {
                        case "setting":
                            configSettings.Add(key, node.Attributes["value"].Value);
                            break;
                        case "listitem":
                            if (!configSettings.ContainsKey(key))
                                configSettings[key] = new List<object>();
                            ((List<object>)configSettings[key]).Add(node.InnerText);
                            break;
                    }
                }
            }

            return configSettings;
        }
        catch (XmlException ex)
        {
            throw new FormatException("Error parsing XML: " + ex.Message, ex);
        }
    }
}